import { queue } from "@trigger.dev/sdk";

// Define a queue with concurrency limit of 1
// This ensures only one task can run at a time globally for this queue
export const criticalQueue = queue({
  name: `critical-queue-placeholder`,
  concurrencyLimit: 1,
});

import { task } from "@trigger.dev/sdk";
import { criticalQueue } from "./queue";

// Define a task that uses the critical queue
// The concurrencyKey ensures only one run per resource ID
export const exclusiveTask = task({
  id: `exclusive-task-placeholder`,
  queue: criticalQueue,
  run: async (payload: { resourceId: string; message?: string }) => {
    // The concurrencyKey is derived from the resourceId in the payload
    // This ensures that only one run per resource ID can execute at a time
    return {
      success: true,
      message: payload.message || "Task completed",
      resourceId: payload.resourceId,
      timestamp: new Date().toISOString(),
    };
  },
  concurrencyKey: async (payload: { resourceId: string }) => {
    // Use the resourceId as the concurrency key
    return `resource:${payload.resourceId}`;
  },
});

